'use strict'

const fs = require('fs')
const path = require('path')

/**
 * Antora extension that publishes the raw .adoc source file alongside each
 * generated HTML page, at the same output path but with a .adoc extension.
 *
 * For example:
 *   stacksaga/latest/introduction-to-stacksaga.html  (generated by Antora)
 *   stacksaga/latest/introduction-to-stacksaga.adoc  (added by this extension)
 */
module.exports.register = function () {
  const adocFiles = []

  this.on('contentClassified', ({ contentCatalog }) => {
    contentCatalog.getPages().forEach((page) => {
      if (!page.out || !page.contents) return
      adocFiles.push({
        outPath: page.out.path.replace(/\.html$/, '.adoc'),
        contents: Buffer.from(page.contents),
      })
    })
  })

  this.on('sitePublished', ({ playbook }) => {
    const outputDir = (playbook.output.destinations || []).reduce(
      (dir, dest) => dest.path || dir,
      playbook.output.dir || 'build/site'
    )
    adocFiles.forEach(({ outPath, contents }) => {
      const fullPath = path.join(outputDir, outPath)
      fs.mkdirSync(path.dirname(fullPath), { recursive: true })
      fs.writeFileSync(fullPath, contents)
    })
  })
}
